using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

builder.Services.AddHostedService<ModelTrainingService>();

var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "TicketModel.zip");
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();
app.MapControllers();

app.MapPost("/api/classify", (PredictionEnginePool<TicketInput, TicketPrediction> pool, TicketInput input) =>
{
    var prediction = pool.Predict(input);

    var categories = new[] { "Billing", "General", "Technical" };
    var scores = new Dictionary<string, float>();
    for (var i = 0; i < prediction.Score.Length && i < categories.Length; i++)
    {
        scores[categories[i]] = prediction.Score[i];
    }

    return Results.Ok(new { PredictedCategory = prediction.PredictedLabel, Confidence = scores });
});

app.Run();

